INSERT INTO `awards` (`id`, `tahun`, `nama_awards`, `nama_awards_id`, `nama_awards_en`, `detail_awards`, `detail_awards_id`, `detail_awards_en`, `link`, `image`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES
(2, '2021-10-09', 'Customer Excellence', 'The Best HR Management', 'The Best HR Management', 'Recognized for outstanding customer service.', 'Perseroan meraih penghargaan The Best HR Management for The Oustanding Excellent Strategies,Values, and Digital Programs to Develop Competent HR untuk kategori Telekomunikasi pada Indonesia Human Resources (HR) Awards 2021.', 'The Company achieved the Best HR Management for The Oustanding Excellent Strategies, Values, and Digital Programs to Develop Competent HR award for the Telecommunications category at the 2021 Indonesia Human Resources (HR) Awards.', NULL, 'https://linknet.co.id//storage/files/1/awards/Award-02s.jpg', 1, 1, '2025-08-27 20:52:34', '2025-11-26 01:49:18'),
(3, '2021-12-22', 'Industry Leadership', 'Human Capital Award', 'Human Capital Award', 'Leadership in industry standards and practices.', 'Perseroan meraih prestasi dalam bidang Sumber Daya Manusia (SDM) dengan meraih 2 (dua) penghargaan sekaligus di ajang Indonesia Human Capital Award VII-2021 berskala nasional bertajuk “Managing People Collaboration Through HC Data Analytics & Technology Savvy in Complex Era”.', 'The Company obtained achievements in the field of Human Resources (HR) by winning 2 (two) awards at the same time at the national-scale Indonesia Human Capital Award VII-2021 entitled “Managing People Collaboration Through HC Data Analytics & Technology Savvy in Complex Era”.', NULL, 'https://linknet.co.id//storage/files/1/awards/Award-04.jpg', 1, 1, '2025-08-27 20:52:34', '2025-11-26 01:59:27'),
(4, '2021-03-14', 'Best Company Award 2024', 'SAP Best Run Awards 2021', 'SAP Best Run Awards 2021', 'Received recognition as the best company in telecommunications sector.', 'Perseroan meraih penghargaan The Best Customer Experience Management dalam acara SAP Best Run Awards 2021 dari Perusahaan piranti lunak multinasional SAP. Penghargaan diberikan kepada Perseroan yang menerapkan teknologi-teknologi SAP, bagaimana teknologi digunakan untuk berinovasi dan mendisrupsi industri untuk mendorong outcome bisnis yang lebih besar.', 'The Company won The Best Customer Experience Management award at the SAP Best Run Awards 2021 from the multinational software company SAP. The award is given to a Company that applies SAP technologies, how technology is used to innovate and disrupt the industry to drive greater business outcomes.', NULL, 'https://linknet.co.id//storage/files/1/awards/Award-03s.jpg', 1, 1, '2025-10-12 07:24:09', '2025-11-26 01:57:01'),
(5, '2021-01-13', 'Innovation Excellence Award', 'Indonesia WOW Brand From MarkPlus Inc', 'Indonesia WOW Brand From MarkPlus Inc', 'Awarded for outstanding innovation in digital transformation.', 'Perseroan dengan brand produk First Media untuk keenam kalinya kembali meraih penghargaan Indonesia WOW Brand dari MarkPlus, Inc. di kategori Pay TV dan penghargaan perdana atas kategori Internet Service.', 'The Company with the First Media product brand for the sixth time won the Indonesia WOW Brand award from MarkPlus, Inc. in the Pay TV category and the first award for the Internet Service category.', NULL, 'https://linknet.co.id//storage/files/1/awards/Award-01s.jpg', 1, 1, '2025-10-12 07:29:13', '2025-11-26 01:54:29'),
(7, '2021-11-26', NULL, 'Top 3 Customer Service Champion', 'Top 3 Customer Service Champion', NULL, 'Perseroan dengan brand “First Media” meraih penghargaan Top 3 Customer Service Champion kategori Data & Entertainment di ajang Indonesia Customer Service Champion 2021, yang diselenggarakan secara virtual bersamaan dengan Indonesia Customer Service Quality Award 2021.', 'The company with the “First Media” brand won the Top 3 Customer Service Champion in the Data & Entertainment category at the Indonesia Customer Service Champion 2021, which was held virtually in conjunction with the Indonesia Customer Service Quality Award 2021.', NULL, 'https://linknet.co.id//storage/files/1/awards/Award-05.jpg', 1, NULL, '2025-11-26 02:04:48', '2025-11-26 02:04:48'),
(8, '2022-11-26', NULL, 'The Best HR Management', 'The Best HR Management', NULL, 'Manajemen SDM Terbaik untuk Ekosistem Sumber Daya Manusia yang Berkualitas Unggul dan Adaptif Melalui Implementasi Digital untuk kategori Industri Telekomunikasi dan Layanan Media.', 'The Best HR Management for The Outstanding Quality and Adaptive Human Resource Ecosystem Through Digital Implementation for the Telecommunication and Media Services Industry category.', NULL, 'https://linknet.co.id//storage/files/1/awards/the-best-hr-management.png', 1, NULL, '2025-11-26 02:09:12', '2025-11-26 02:09:12'),
(9, '2022-11-26', NULL, 'Indonesia Best Millennials’ Brand Choice 2022', 'Indonesia Best Millennials’ Brand Choice 2022', NULL, 'Penghargaan untuk kategori TV Kabel, Outstanding Millennials’ Brand Choice 2022 untuk kategori Internet Provider dan Indonesia Very Good Millennials’ Brand Choice 2022 untuk kategori Internet Provider', 'Award for the Cable TV category, Outstanding Millennials’ Brand Choice 2022 for the Internet Provider category and Indonesia Very Good Millennials’ Brand Choice 2022 for the Internet Provider category', NULL, 'https://linknet.co.id//storage/files/1/awards/Indonesia-Best-Millennials’-Brand-Choice-2022.png', 1, NULL, '2025-11-26 02:10:15', '2025-11-26 02:10:15'),
(10, '2022-11-26', NULL, '2022 ICXC and 2022 ISTC', '2022 ICXC and 2022 ISTC', NULL, 'Juara Pengalaman Pelanggan Indonesia (ICXC) 2022 dan Juara Tim Penjualan Indonesia (ISTC) 2022', '2022 Indonesia Customer Experience Champions (ICXC) and 2022 Indonesia Sales Team Champions (ISTC)', NULL, 'https://linknet.co.id//storage/files/1/awards/Indonesia-Customer-Experience.png', 1, NULL, '2025-11-26 02:11:27', '2025-11-26 02:11:27'),
(11, '2022-11-26', NULL, 'Indonesia Digital Marketing Champion 2022', 'Indonesia Digital Marketing Champion 2022', NULL, '- Best Digital Marketing Team\r\n- Best Digital Brand Award 2022 in the Internet Provider category', '- Best Digital Marketing Team\r\n- Best Digital Brand Award 2022 in the Internet Provider category', NULL, 'https://linknet.co.id//storage/files/1/awards/indonesia-Digital-Marketing-Champion.png', 1, NULL, '2025-11-26 02:12:27', '2025-11-26 02:12:27'),
(12, '2023-11-26', NULL, 'WOW Brand Festive Day', 'WOW Brand Festive Day', NULL, 'Indonesia WOW Brand Award 2023', 'Indonesia WOW Brand Award 2023', NULL, 'https://linknet.co.id//storage/files/1/awards/2023/Indonesia-WOW-Brand-Award-2023.png', 1, NULL, '2025-11-26 02:19:03', '2025-11-26 02:19:03'),
(13, '2023-11-26', NULL, 'B-Universe CSR Awards', 'B-Universe CSR Awards', NULL, 'CSR Awards 2023 pada kategori infrastruktur untuk inisiatif corporate social responsibility, Empowering Fund.', 'CSR Awards 2023 in the infrastructure category for the corporate social responsibility initiative, Empowering Fund.', NULL, 'https://linknet.co.id//storage/files/1/awards/2023/B-Universe-CSR-Awards.png', 1, NULL, '2025-11-26 02:20:56', '2025-11-26 02:20:56'),
(14, '2023-11-26', NULL, 'Penghargaan Sistem Manajemen Keselamatan', 'Occupational Health', NULL, 'Penghargaan Sistem Manajemen Keselamatan dan Kesehatan Kerja an Occupational Safety and Health Management System award', 'Occupational Safety and Health Management System Award', NULL, 'https://linknet.co.id//storage/files/1/awards/2023/Occupational-Health-and-Safety-Management-System-Award.png', 1, NULL, '2025-11-26 02:22:23', '2025-11-26 02:22:23'),
(15, '2023-11-26', NULL, 'Contact Center World Award 2023', 'Contact Center World Award 2023', NULL, 'Kategori Perusahaan : \r\n\r\n1. Best Home/Remote Agent Program (Silver), dan; \r\n2. Best use of Self-service Technology (Bronze).\r\n\r\nkategori Individu : \r\n\r\n\r\n1. Best Contact Center Executive/Director (Gold), dan; \r\n2. Best Quality Auditor (Bronze).', 'Kategori Perusahaan : \r\n\r\n1. Best Home/Remote Agent Program (Silver), dan; \r\n2. Best use of Self-service Technology (Bronze).\r\n\r\nkategori Individu : \r\n\r\n\r\n1. Best Contact Center Executive/Director (Gold), dan; \r\n2. Best Quality Auditor (Bronze).', NULL, 'https://linknet.co.id//storage/files/1/awards/2023/Contact-Center-World-Award-2023.png', 1, NULL, '2025-11-26 02:24:03', '2025-11-26 02:24:03'),
(16, '2023-11-26', NULL, 'Penghargaan Zero Accident', 'Platinum Award for Zero Accident', NULL, 'Penghargaan Zero Accident dan Program Pencegahan dan Penanggulangan Covid-19 di tempat kerja dengan kategori Platinum.', 'Platinum Award for Zero Accident and Covid-19 Prevention and Response Program in the Workplace.', NULL, 'https://linknet.co.id//storage/files/1/awards/2023/penghargaan-Zero-Accident.png', 1, NULL, '2025-11-26 02:25:29', '2025-11-26 02:25:29'),
(17, '2023-11-26', NULL, 'TrenAsia ESG Award', 'TrenAsia ESG Award', NULL, 'Penghargaan di TrenAsia ESG Award kategori internet service provider dengan kategori sustainability.', 'Award at the TrenAsia ESG Award in the internet service provider category with the sustainability category.', NULL, 'https://linknet.co.id//storage/files/1/awards/2023/TrenAsia-ESG-Award.png', 1, NULL, '2025-11-26 02:27:08', '2025-11-26 02:27:08'),
(18, '2023-11-26', NULL, 'The Best Contact Center Indonesia 2023', 'The Best Contact Center Indonesia 2023', NULL, '5 penghargaan kategori Corporate dengan sub kategori sebagai berikut :\r\n\r\n1. 2 Platinum awards for Best People Development and Best Business Contribution;\r\n2. One Gold award for Best Technology Innovation;\r\n3. Two Silver awards for Best Customer Experience and Best Contact Center Operations.', 'Five awards in the Corporate category, with the following subcategories:\r\n\r\n1. Two Platinum awards for Best People Development and Best Business Contribution;\r\n2. One Gold award for Best Technology Innovation;\r\n3. Two Silver awards for Best Customer Experience and Best Contact Center Operations.', NULL, 'https://linknet.co.id//storage/files/1/awards/2023/The-Best-Contact-Center-Indonesia-2023.png', 1, NULL, '2025-11-26 02:29:27', '2025-11-26 02:29:27'),
(19, '2023-11-26', NULL, '18th Annual Global Top Ranking Performer Awards', '18th Annual Global Top Ranking Performer Awards', NULL, 'Gold Medal untuk kategori Best Home/Remote Agent Program dan Silver Medal untuk kategori Best Leader', 'Gold Medal for the Best Home/Remote Agent Program category and Silver Medal for the Best Leader category', NULL, 'https://linknet.co.id//storage/files/1/awards/2023/18th-Annual-Global-Top-Ranking-Performer-Awards.png', 1, NULL, '2025-11-26 02:30:27', '2025-11-26 02:30:27'),
(20, '2024-11-26', NULL, 'SWA-Business Digest Brand Awarding', 'SWA-Business Digest Brand Awarding', NULL, 'Indonesia Original Brand (IOB) Award 2024', 'Indonesia Original Brand (IOB) Award 2024', NULL, 'https://linknet.co.id//storage/files/1/awards/2024/SWA-Business-Digest-Brand-Awarding.png', 1, NULL, '2025-11-26 02:32:48', '2025-11-26 02:32:48'),
(21, '2024-11-26', NULL, 'Jawa Pos 7 Most Popular Brand of The Year', 'Jawa Pos 7 Most Popular Brand of The Year', NULL, 'Jawa Pos 7 Merek Terpopuler Tahun 2024', 'Jawa Pos 7 Most Popular Brand of The Year 2024', NULL, 'https://linknet.co.id//storage/files/1/awards/2024/Jawa-Pos-7-Most-Popular-Brand-of-The-Year.png', 1, NULL, '2025-11-26 02:33:44', '2025-11-26 02:33:44'),
(22, '2024-11-26', NULL, 'Recognizing Strategic Vision, Rewarding Excellence', 'Recognizing Strategic Vision, Rewarding Excellence', NULL, 'Penghargaan Perusahaan Publik Terbaik Indonesia 2024 dan Penghargaan CMO Terbaik Indonesia 2024', 'Penghargaan Perusahaan Publik Terbaik Indonesia 2024 dan Penghargaan CMO Terbaik Indonesia 2024', NULL, 'https://linknet.co.id//storage/files/1/awards/2024/Indonesia-Best-Public-Company.png', 1, NULL, '2025-11-26 02:34:48', '2025-11-26 02:34:48');


--
-- Table structure for table `managements`
--

CREATE TABLE `managements` (
  `id` bigint UNSIGNED NOT NULL,
  `name` varchar(191) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `position_en` varchar(191) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `position_id` varchar(191) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `category` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `category_id` bigint UNSIGNED DEFAULT NULL,
  `photo` varchar(191) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `bio_en` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `bio_id` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `data_order` int DEFAULT NULL,
  `data_status` int NOT NULL DEFAULT '1',
  `created_by` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `updated_by` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL
) ENGINE=MyISAM DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

--
-- Dumping data for table `managements`
--

INSERT INTO `managements` (`id`, `name`, `position_en`, `position_id`, `category`, `category_id`, `photo`, `bio_en`, `bio_id`, `data_order`, `data_status`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES
(1, 'Vivek Sood', 'President Commissioner', NULL, NULL, 1, 'https://linknet.co.id/storage/files/1/management/Vivek Sood.jpg', '<p>Mr Vivek, an Indian citizen, appointed as President Commissioner of the Company based on the Extraordinary General Meeting of Shareholders (EGMS) as stated in the Deed of Meeting Resolution No. 168 dated 23 January 2025.</p><p>Prior served as Commissioner of the Company since February 2024. Having experience as the Executive Vice President and Group Chief Marketing Officer of Telenor Group, as CFO and CEO of Telenor India, CEO of Grameenphone (Bangladesh), and Chief Operating Officer and CFO of Tata AIA Life Insurance (India). Currently, serves as Group Chief Executive Officer (GCEO) and Managing Director of Axiata Group Berhad (Axiata) since March 2023 after serving as Joint Acting GCEO since June 2022 and as Group Chief Financial Officer (CFO) in 2017. Besides that, he also served as a Commissioner of PT XL Axiata Tbk since 2017.</p>', '<p>Bapak Vivek, kewarganegaraan India, diangkat sebagai Presiden Komisaris Perseroan berdasarkan Rapat Umum Pemegang Saham Luar Biasa (RUPSLB) yang dituangkan dalam Akta Pernyataan Keputusan Rapat No. 168 tanggal 23 Januari 2025.</p><p>Sebelumnya menjabat sebagai Komisaris Perseroan sejak Februari 2024. Memiliki pengalaman sebagai Executive Vice President dan Group Chief Marketing Officer di Telenor Group, menjabat sebagai CFO dan CEO di Telenor India, menjabat sebagai CEO di Grameenphone (Bangladesh), serta Chief Operating Officer dan CFO di Tata AIA Life Insurance (India). Saat ini, menjabat sebagai Group Chief Executive Officer (GCEO) and Managing Director of Axiata Group Berhad (Axiata) sejak Maret 2023, setelah sebelumnya menjabat Joint Acting GCEO sejak Juni 2022 dan Group Chief Financial Officer (GCFO) pada 2017. Disamping itu, beliau juga menjabat sebagai Komisaris PT XL Axiata Tbk sejak 2017</p>', 1, 1, NULL, 'admin@gmail.com', '2025-10-11 23:58:24', '2025-11-26 07:43:08'),
(2, 'Thomas Hundt', 'Commissioner', NULL, NULL, 1, 'https://linknet.co.id/storage/files/1/management/Thomas Hundt.jpg', '<p>Mr. Thomas Hundt was born in Blankenburg/Hraz, Germany. Germany citizenship domicile in Malaysia, age 45 years. Appointed as Commissioner of the Company based on the Annual General Meeting of Shareholders (AGMS) as stated in the Deed of Meeting Resolution No. 41 dated June 22, 2022.</p><p>He has vast experience in the telecommunication industry including at Siemens AG Germany from 1998 to 2007 with his last position as Director Commercial Sales, Member of Supervisory Board of Azerfon LLC Azerbaijan from 2005 to 2006, Executive Project Manager and CFO CMO North-East Finance &amp; Control di Nokia Siemens Network GmBH &amp; Co. KG Germany from 2007 to 2008, Member of Advisory Board AIESEC Cambodia from 2013 to 2019, Board Member of European Chamber of Commerce (Eurocham) Cambodia from 2011, Vice President German Business Group (ADW) Kamboja from 2010, and joined with Axiata Group Company since 2014 and served various director positions, with his last position as Group Chief Strategy &amp; Technology Officer of Axiata Group Berhad.</p>', '<p>Bapak Thomas Hundt lahir di Blankenburg/Hraz, Jerman. Warga Negara Jerman berdomisili di Malaysia, usia 45 tahun. Diangkat sebagai Komisaris Perseroan berdasarkan Rapat Umum Pemegang Saham Tahunan (RUPST) yang dituangkan dalam Akta Pernyataan Keputusan Rapat No. 41 tanggal 22 Juni 2022.</p><p>Beliau memiliki pengalaman luas di industri telekomunikasi diantaranya pada Siemens AG Jerman sejak tahun 1998 sampai dengan tahun 2007 dengan posisi terakhir sebagai Director Commercial Sales, sebagai Anggota Dewan Pengawasan Azerfon LLC Azerbaijan pada tahun 2005 sampai dengan tahun 2006, sebagai Executive Project Manager dan CFO CMO North-East Finance &amp; Control di Nokia Siemens Network GmBH &amp; Co. KG Jerman pada tahun 2007 sampai dengan tahun 2008, sebagai Anggota Dewan Penasihat di AIESEC Kamboja pada tahun 2013 sampai dengan tahun 2019, sebagai Anggota Dewan Kamar Dagang Eropa (Eurocham) Kamboja sejak tahun 2011, sebagai Vice President German Business Group (ADW) Kamboja sejak tahun 2010, dan bergabung bersama Axiata Group Company sejak tahun 2014 dan menjabat pada berbagai posisi direktur, dengan posisi terakhir saat ini sebagai Group Chief Strategy &amp; Technology Officer di Axiata Group Berhad.</p>', 2, 1, NULL, 'admin@gmail.com', '2025-10-11 23:58:24', '2025-11-26 07:46:36'),
(3, 'Alexander S. Rusli', 'Independent Commissioner', NULL, NULL, 1, 'https://linknet.co.id/storage/files/1/management/Alexander-S-Rusli.jpg', '<p>Mr. Alexander S. Rusli was born in Sydney, Australia. An Indonesian citizen domiciled in Jakarta, aged 50. He holds a PhD in Information Technology from Curtin University of Technology. He was appointed as an Independent Commissioner of the Company in 2020 and re-appointed based on the Annual General Meeting of Shareholders (AGMS) as stated in the Deed of Meeting Resolution No. 41 dated June 22, 2022.</p><p>Mr. Alexander Rusli is a proven technology leader with a strong track record in driving change. Prior to joining the Company, he served as CEO of Indosat Ooredoo from 2012 to 2017, and previously spent nine years as Special Staff to the Minister at the Ministry of Communication and Informatics and the Ministry of State-Owned Enterprises. He has held Board positions at several SOEs, including Krakatau Steel, Geo Dipa Energi, and PT Kertas Kraft Aceh, and was an Independent Commissioner at PT Sarana Menara Nusantara Tbk (Protelindo) from 2018 to 2019. He currently serves as Independent Commissioner at PT Unilever Indonesia Tbk (since 2018) and at Hermina Hospital Group (since 2018), is the Founder of Digiasia Bios, and is an owner of a joint venture with Tempo Digital Media focusing on animation for Indonesian IP characters.</p>', '<p>Bapak Alexander S. Rusli lahir di Sydney, Australia. Warga Negara Indonesia berdomisili di Jakarta, usia 50 tahun. Bapak Alexander Rusli meraih gelar PhD Degree dalam Information Technology dari Curtin University of Technology. Beliau diangkat sebagai Komisaris Independen Perseroan sejak tahun 2020, dan diangkat kembali berdasarkan Rapat Umum Pemegang Saham Tahunan (RUPST) yang dituangkan dalam Akta Pernyataan Keputusan Rapat No. 41 tanggal 22 Juni 2022.</p><p>Bapak Alexander Rusli merupakan sosok yang kompeten, mampu menciptakan perubahan dan memiliki pengalaman serta latar belakang yang kuat di bidang teknologi. Sebelum bergabung dengan Perseroan, Bapak Alexander Rusli merupakan CEO di Indosat Oredoo pada tahun 2012 sampai dengan 2017, yang kemudian menjadikan Indosat Oredoo, operator telekomunikasi terbesar ke-2 di Indonesia dengan jumlah 100 juta pelanggan, tercatat di Bursa Efek Indonesia. Beliau juga pernah menjabat sebagai Staf Khusus Menteri selama 9 tahun di Kementerian Komunikasi dan Informatika serta Kementerian BUMN, Board Members di berbagai perusahaan BUMN seperti Krakatau Steel, Geodipa Energi dan PT Kertas Kraft Aceh, dan sebagai Komisaris Independen di PT Sarana Menara Nusantara Tbk (Protelindo) pada tahun 2018 sampai dengan 2019. Saat ini Beliau masih menjabat di beberapa perusahaan yaitu sebagai Komisaris Independen di PT Unilever Indonesia Tbk sejak tahun 2018, Komisaris Independen di Hermina Hospital Group sejak tahun 2018, Pendiri dari Digiasia Bios, dan Pemilik Joint Venture dengan Tempo Digital Media yang berfokus pada animasi untuk Indonesian IP characters.</p>', 4, 1, NULL, 'admin@gmail.com', '2025-10-11 23:58:24', '2025-11-26 07:48:07'),
(4, 'Kanishka Gayan Wickrama', 'President Director', NULL, NULL, 2, 'https://linknet.co.id//storage/files/1/management/Kanishka G Wickrama 1_1 2.png', '<p>Mr. Kanishka Gayan Wickrama, a Sri Lanka citizen. Appointed as President Director of the Company based on the Extraordinary General Meeting of Shareholders (EGMS) as stated in the Deed of Meeting Resolution No. 168 dated 23 January 2025, previously served as Director since November 2022.</p><p>He has almost 20 years of experience and exposure in telecommunication industry. He is a seasoned executive within Axiata Group Berhad. Started his career with Axiata Group in Dialog Axiata PLC., prior joining PT Link Net Tbk as CFO, he served as CFO of Ncell (Nepal) and Smart Axiata (Cambodia).</p>', '<p>Bapak Kanishka Gayan Wickrama, warga Negara Sri Lanka. Beliau diangkat sebagai Presiden Direktur Perseroan berdasarkan Rapat Umum Pemegang Saham Luar Biasa (RUPSLB) yang dituangkan dalam Akta Pernyataan Keputusan Rapat No. 168 tanggal 23 Januari 2025, setelah sebelumnya menjabat sebagai Direktur sejak November 2022.</p><p>Beliau memiliki hampir 20 tahun pengalaman dan ketertarikan dalam industry telekomunikasi. Beliau adalah eksekutif berpengalaman di Axiata Group Berhad. Mengawali karirnya bersama Axiata Group di Dialog Axiata PLC., sebelum bergabung bersama PT Link Net Tbk sebagai Chief Financial Officer (CFO), beliau pernah menjabat sebagai CFO di Ncell (Nepal) dan Smart Axiata (Kamboja).</p>', 5, 1, NULL, 'admin@gmail.com', '2025-10-11 23:58:24', '2025-11-26 07:50:05'),
(5, 'Yosafat Marhasak Hutagalung', 'Director', NULL, NULL, 2, 'https://linknet.co.id//storage/files/1/management/Yosafat Hutagalung 2 2.png', '<p>Indonesian Nationality.</p><p>He served in the Company from November 2014, with roles as the Head of Human Resources Function, and Strategic Management office in 2018 until 2019. Since 1 August 2020 he was appointed as a Chief Human Capital Officer of the Company.</p><p>Before joining the Company, He experienced in human resource management for more than 20 years in various industries such as heavy industries equipment, education, financial services, property/real estate, mining services, information technology, and human resources consultant.</p><p>Appointed as a Director of the Company based on the Resolution of Extraordinary General Meeting of Shareholders dated 12 February 2024.</p>', '<p>Kewarganegaraan Indonesia.</p><p>Bergabung bersama Perseroan sebagai Head of Human Resources Function sejak November 2014, dan sempat juga mengelola Strategic Management Office (SMO) selama satu tahun 2018-2019. Semenjak 1 Agustus 2020 ditunjuk sebagai Chief Human Capital Officer Perseroan.</p><p>Sebelum bergabung Bersama Perseroan, beliau berpengalaman di bidang pengelolaan sumber daya manusia selama lebih dari 20 tahun dengan berbagai perusahaan dari beragam industri seperti alat – alat berat, pendidikan, jasa keuangan, properti, pertambangan, teknologi Informasi, dan juga konsultan sumber daya manusia.</p><p>Diangkat menjadi Direktur Perseroan berdasarkan Keputusan Rapat Umum Pemegang Saham Luar Biasa tanggal 12 Februari 2024.</p>', 6, 1, NULL, 'admin@gmail.com', '2025-10-11 23:58:24', '2025-11-26 07:50:47'),
(6, 'Thandalam Veeravalli Thirumala Chari', 'Independent Commissioner', NULL, NULL, 1, 'https://linknet.co.id/storage/files/1/management/Thandalam Veeravalli Thirumala Chari.png', '<p>Mr Chari, a Indian citizen, appointed as Independent Commissioner of the Company based on the General Meeting of Shareholders of the Company in 21 May 2025.</p><p>Mr. Chari is a senior finance professional (retired CFO) with over 44 years of experience in the Technology and Telecom sectors across Asia Pacific. He has overseen successful strategic transformations of the organizations and received external recognition for the highest profits and ROIC in the industry. He has significant corporate governance experience as a senior executive and director on four large listed and unlisted company boards influencing key stakeholders to steer businesses to deliver results. He also has experience of leading cultural change, building cross-functional leadership teams and organizational capabilities. He has also spent 10 years in Sales and Marketing at Hewlett Packard, making him wellrounded and capable of providing balanced strategic advice.”</p><p>He currently serves as a consultant and financial advisor. And, in his ”down time” enjoys presenting papers at many external forums and assisting the next generation by mentoring and coaching.</p>', '<p>Bapak Chari, kewarganegaraan India, diangkat sebagai Komisaris Independen Perseroan berdasarkan Rapat Umum Pemegang Saham Perseroan tanggal 21 Mei 2025.</p><p>Bapak Chari adalah seorang profesional keuangan senior (pensiunan CFO) dengan lebih dari 44 tahun pengalaman di sektor Teknologi dan Telekomunikasi di seluruh Asia Pasifik. Beliau telah mengawasi transformasi strategis yang sukses di berbagai organisasi dan menerima pengakuan eksternal untuk keuntungan dan ROIC tertinggi di industri ini. Beliau memiliki pengalaman tata kelola perusahaan yang signifikan sebagai eksekutif senior dan direktur di empat perusahaan besar yang terdaftar dan tidak terdaftar di bursa saham yang mempengaruhi para pemangku kepentingan utama untuk mengarahkan bisnis agar memberikan hasil. Beliau juga memiliki pengalaman dalam memimpin perubahan budaya, membangun tim kepemimpinan lintas fungsi dan kapabilitas organisasi. Beliau juga telah menghabiskan 10 tahun di bidang Penjualan dan Pemasaran di Hewlett Packard, sehingga menjadikan beliau memiliki pengetahuan yang luas dan mampu memberikan nasihat strategis yang berimbang.\"</p><p>Saat ini beliau menjabat sebagai konsultan dan penasihat keuangan. Dan, di “waktu senggangnya”, ia senang mempresentasikan makalah di berbagai forum eksternal dan membantu generasi berikutnya dengan memberikan bimbingan dan pelatihan.</p>', 7, 1, NULL, 'admin@gmail.com', '2025-10-11 23:58:24', '2025-12-04 05:52:12'),
(7, 'Rininta Agustina', 'Corporate Secretary', NULL, 'corporate_secretary', 3, 'https://linknet.co.id/storage/files/1/management/Rininta Agustina.jpg', 'She began her career at PT Astra Graphia Tbk as a Legal Analyst in 2008 and later served as Corporate Secretary and Head of the Legal Department in 2020; she was Corporate Secretary Manager at PT Bali Towerindo Sentra Tbk in 2023. She joined the Company in November 2023.\r\n\r\nShe was appointed as Corporate Secretary based on the resolution of the Board of Directors of the Company dated February 12, 2024.', NULL, 8, 1, NULL, 'admin@gmail.com', '2025-10-11 23:58:24', '2025-10-13 13:34:06'),
(8, 'Nik Rizal Kamil', 'Commissioner', NULL, NULL, 1, 'https://linknet.co.id/storage/files/1/management/Nik Rizal Kamil.png', '<p>Mr. Nik, a Malaysian citizen, was appointed as Commissioner of the Company based on the Extraordinary General Meeting of Shareholders (EGMS) as stated in the Deed of Meeting Resolution No. 168 dated January 23, 2025.</p><p>He has extensive experience in accounting, finance, and investment. He has held strategic positions in several companies in Malaysia, including serving as Group Chief Financial Officer (CFO) at RHB Bank, Executive Director at Khazanah Nasional, and Board Member at Telekom Malaysia and Astro Malaysia Holdings Berhad. Currently, he is the Group Chief Financial Officer (GCFO) of Axiata Group Berhad as well as Commissioner of PT XL Axiata Tbk.</p>', '<p>Bapak Nik, kewarganegaraan Malaysia, diangkat sebagai Komisaris Perseroan berdasarkan Rapat Umum Pemegang Saham Luar Biasa (RUPSLB) yang dituangkan dalam Akta Pernyataan Keputusan Rapat No. 168 tanggal 23 Januari 2025.</p><p>Memiliki pengalaman dalam bidang akuntansi, keuangan, dan investasi. Menduduki jabatan strategis di beberapa perusahaan di Malaysia, diantaranya sebagai Group CFO di RHB Bank, sebagai Direktur Eksekutif di Khazanah Nasional, serta menjabat sebagai anggota Dewan di Telekom Malaysia dan Astro Malaysia Holdings Berhad. Saat ini, beliau menjabat sebagai Group Chief Financial Officer (GCFO) Axiata Group Berhad (Axiata Group) serta Komisaris PT XL Axiata Tbk.</p>', 3, 1, 'admin@gmail.com', 'admin@gmail.com', '2025-10-13 13:31:23', '2025-11-26 07:47:29'),
(9, 'Thandalam Veeravalli Thirumala Chari', 'Chairman of Audit Committee', 'Chairman of Audit Committee', NULL, 4, 'https://linknet.co.id//storage/files/1/management/Thandalam Veeravalli Thirumala Chari.png', '<p>A senior finance professional (retired CFO) with over 44 years of experience in the Technology and Telecom sectors across Asia Pacific. He has overseen successful strategic transformations of the organizations and received external recognition for the highest profits and ROIC in the industry. He has significant corporate governance experience as a senior executive and director on four large listed and unlisted company boards influencing key stakeholders to steer businesses to deliver results. He also has experience of leading cultural change, building cross-functional leadership teams and organizational capabilities. He has also spent 10 years in Sales and Marketing at Hewlett Packard, making him wellrounded and capable of providing balanced strategic advice.”&nbsp;</p><p>He currently serves as a consultant and financial advisor. And, in his ”down time” enjoys presenting papers at many external forums and assisting the next generation by mentoring and coaching.</p>', '<p>Seorang profesional keuangan senior (pensiunan CFO) dengan lebih dari 44 tahun pengalaman di sektor Teknologi dan Telekomunikasi di seluruh Asia Pasifik. Beliau telah mengawasi transformasi strategis yang sukses di berbagai organisasi dan menerima pengakuan eksternal untuk keuntungan dan ROIC tertinggi di industri ini. Beliau memiliki pengalaman tata kelola perusahaan yang signifikan sebagai eksekutif senior dan direktur di empat perusahaan besar yang terdaftar dan tidak terdaftar di bursa saham yang mempengaruhi para pemangku kepentingan utama untuk mengarahkan bisnis agar memberikan hasil. Beliau juga memiliki pengalaman dalam memimpin perubahan budaya, membangun tim kepemimpinan lintas fungsi dan kapabilitas organisasi. Beliau juga telah menghabiskan 10 tahun di bidang Penjualan dan Pemasaran di Hewlett Packard, sehingga menjadikan beliau memiliki pengetahuan yang luas dan mampu memberikan nasihat strategis yang berimbang.\"&nbsp;</p><p>Saat ini beliau menjabat sebagai konsultan dan penasihat keuangan. Dan, di “waktu senggangnya”, ia senang mempresentasikan makalah di berbagai forum eksternal dan membantu generasi berikutnya dengan memberikan bimbingan dan pelatihan.</p>', NULL, 1, 'admin@gmail.com', NULL, '2025-11-28 09:38:10', '2025-11-28 09:38:10'),
(10, 'Alexander S Rusli', 'Member of Audit Committee', 'Member of Audit Committee', NULL, 4, 'https://linknet.co.id//storage/files/1/management/Alexander-S-Rusli.jpg', '<p>Began his career as a Senior Consultant at PricewaterhouseCoopers Consulting Asia Pacific (1997-2001), then served as a Special Advisor at the Ministry of Communication and Information Technology (2001-2007) and the Ministry of State-Owned Enterprises (2007-2009). He has also served on the boards of various state-owned companies, including Commissioner at PT Krakatau Steel (Persero) Tbk (2007-2009), Commissioner at PT Kertas Kraft Aceh (Persero) (2007-2009), and President Commissioner at PT Geodipa Energi (Persero) (2007- 2009). Furthermore, he has held positions such as Managing Director at PT Northstar Pacific Capital (2009-2012), Independent Commissioner and President Director at PT Indosat Tbk (2010-2017), Independent Commissioner at PT Asuransi Tugu Pratama Indonesia Tbk (2011-2013), Independent Commissioner at PT Sarana Menara Nusantara Tbk (Protelindo) (2018-2019), Chairman at Iflix Indonesia (2018-2020), and Commissioner at PT Solusi Sinergi Digital (2019-2022).</p>', '<p>Memulai karirnya sebagai Senior Consultant di PrincewaterhouseCoopers Consulting Asia Pacific (1997-2001), kemudian menjabat sebagai Special Advisor di Kementerian Komunikasi dan Informatika (2001-2007) dan Kementerian BUMN (2007-2009). Beliau juga menjabat di berbagai perusahaan BUMN diantaranya sebagai Komisaris di PT Krakatau Steel (Persero) Tbk (2007-2009), sebagai Komisaris di PT Kertas Kraft Aceh (Persero) (2007-2009), sebagai Presiden Komisaris di PT Geodipa Energi (Persero) (2007-2009). Selain itu, Beliau juga menjabat sebagai Managing Director di PT Northstar Pacific Capital (2009-2012), sebagai Independen Komisaris dan Presiden Direktur di PT Indosat Tbk (2010-2017), serta sebagai Komisaris Independen di PT Asuransi Tugu Pratama Indonesia Tbk (2011-2013) Komisaris Independen di PT Sarana Menara Nusantara Tbk (Protelindo) (2018-2019), Chairman di Iflix Indonesia (2018-2020), dan Komisaris PT Solusi Sinergi Digital (2019-2022). &nbsp;</p>', NULL, 1, 'admin@gmail.com', NULL, '2025-11-28 09:39:15', '2025-11-28 09:39:15'),
(11, 'Tio I Huat', 'Member of Audit Committee', 'Member of Audit Committee', NULL, 4, 'https://linknet.co.id//storage/files/1/management/Tio I Huat.jpg', '<p>Indonesian citizen, 47 years old, born in Pematang Siantar.</p><p>Hold a bachelor\'s degree in economic majoring in accounting from Krida Wacana Christian University.</p><p>Joined with PT Indofood Sukses Makmur-Bogasri Flour Mills as Account Officer (1995-1997), Senior Auditor at Prasetio Utomo &amp; Co (1997-1999), Manager of PT Cakrawala Mega Indah (1999-2006), Senior Manager at Argo Manunggal Group on 2006, appointed as Director of PT Menamas Mitra Energi subsidiary of PT Truba Alam Manunggal Tbk (2007-2014), Head of Internal Audit at PT Nirvana Development Tbk (2014-2015), as Group Finance Controller at Samko Timber(2016-2017), as Head of Corporate Log Procurement at Samko Timber, (2017– present), dan as Independent director of PT Lontar Papyrus Pulp &amp; Paper (2018-2020).</p>', '<p>Warga negara Indonesia, berusia 47 tahun, lahir di Pematang Siantar.</p><p>Memegang gelar sarjana ekonomi dengan jurusan akuntansi dari Universitas Kristen Krida Wacana.</p><p>Pernah bergabung dengan PT Indofood Sukses Makmur-Bogasri Flour Mills sebagai Account Officer (1995-1997), Senior Auditor di Prasetio Utomo &amp; Co (1997-1999), Manajer PT Cakrawala Mega Indah (1999-2006), Manajer Senior di Argo Manunggal Group pada tahun 2006, ditunjuk sebagai Direktur PT Menamas Mitra Energi anak perusahaan PT Truba Alam Manunggal Tbk (2007-2014), Kepala Audit Internal di PT Nirvana Development Tbk (2014-2015), sebagai Group Finance Controller di Samko Timber (2016-2017), sebagai Head of Corporate Log Procurement di Samko Timber, (2017-sekarang), dan sebagai direktur Independen di PT Lontar Papyrus Pulp &amp; Paper (2018-2020).</p>', NULL, 1, 'admin@gmail.com', NULL, '2025-11-28 09:40:45', '2025-11-28 09:40:45'),
(12, 'Barry Alfa Rattu', 'Member of Audit Committee', 'Member of Audit Committee', NULL, 4, 'https://linknet.co.id//storage/files/1/management/Barry Alfa Rattu.jpg', '<p>Indonesian citizen, 47 years old, born in Tomohon.</p><p>Hold Bachelor of Management Information from Bina Nusantara University Jakarta.</p><p>Started career as Senior Sales at PT Astra International Tbk - Toyota Sales Operation (Auto 2000) (1994-1997), served in several positions at PT Pindo Deli Pulp and Paper Mills (Sinar Mas Group) with last position as Deputy Head of Finance and Accounting Management By Olympic System (MBOS) (1998-2005). as Business Process Improvement Manager at PT Argo Pantes Tbk (2005-2006), as General Manager of Business Process Improvement and HR at PT Alam Sutera Realty Tbk and PT Pralon (2006-2011), served in&nbsp;several positions at PT Bekasi Fajar Industrial Estate Tbk with last position as Head of CEO Office (2011-2016), Director of PT Makmur Abadi Selaras (2016-2018), as General Manager Sales &amp; Marketing at PT Panca Terang Abadi (Artha Industrial Hill – ARTHA GRAHA Group) on 2017, and As General Manager of Operational Core Business: Crewing, HRGA &amp; IT at PT Trans Power Marine Tbk (2017-present).</p>', '<p>Warga negara Indonesia, berusia 47 tahun, lahir di Tomohon.</p><p>Memegang gelar Sarjana Manajemen Informatika dari Universitas Bina Nusantara Jakarta.</p><p>Memulai karier sebagai Senior Sales di PT Astra International Tbk – Toyota Sales Operation (Auto 2000) (1994–1997), menjabat dalam beberapa posisi di PT Pindo Deli Pulp and Paper Mills (Sinar Mas Group) dengan posisi terakhir sebagai Deputy Head of Finance and Accounting Management By Olympic System (MBOS) (1998–2005). Pernah menjadi Business Process Improvement Manager di PT Argo Pantes Tbk (2005–2006), General Manager Business Process Improvement and HR di PT Alam Sutera Realty Tbk dan PT Pralon (2006–2011), menjabat dalam beberapa posisi di PT Bekasi Fajar Industrial Estate Tbk dengan posisi terakhir sebagai Head of CEO Office (2011–2016), Direktur PT Makmur Abadi Selaras (2016–2018), General Manager Sales &amp; Marketing di PT Panca Terang Abadi (Artha Industrial Hill – ARTHA GRAHA Group) pada 2017, dan sebagai General Manager Operational Core Business: Crewing, HRGA &amp; IT di PT Trans Power Marine Tbk (2017–sekarang).</p>', NULL, 1, 'admin@gmail.com', NULL, '2025-11-28 09:42:23', '2025-11-28 09:42:23'),
(13, 'Alexander S. Rusli', 'Chairman of Nomination and Remuneration Committee', 'Chairman of Nomination and Remuneration Committee', NULL, 5, 'https://linknet.co.id//storage/files/1/management/Alexander-S-Rusli.jpg', '<p>Began his career as a Senior Consultant at PricewaterhouseCoopers Consulting Asia Pacific (1997-2001), then served as a Special Advisor at the Ministry of Communication and Information Technology (2001-2007) and the Ministry of State-Owned Enterprises (2007-2009). He has also served on the boards of various state-owned companies, including Commissioner at PT Krakatau Steel (Persero) Tbk (2007-2009), Commissioner at PT Kertas Kraft Aceh (Persero) (2007-2009), and President Commissioner at PT Geodipa Energi (Persero) (2007- 2009). Furthermore, he has held positions such as Managing Director at PT Northstar Pacific Capital (2009-2012), Independent Commissioner and President Director at PT Indosat Tbk (2010-2017), Independent Commissioner at PT Asuransi Tugu Pratama Indonesia Tbk (2011-2013), Independent Commissioner at PT Sarana Menara Nusantara Tbk (Protelindo) (2018-2019), Chairman at Iflix Indonesia (2018-2020), and Commissioner at PT Solusi Sinergi Digital (2019-2022).</p>', '<p>Memulai karirnya sebagai Senior Consultant di PrincewaterhouseCoopers Consulting Asia Pacific (1997-2001), kemudian menjabat sebagai Special Advisor di Kementerian Komunikasi dan Informatika (2001-2007) dan Kementerian BUMN (2007-2009). Beliau juga menjabat di berbagai perusahaan BUMN diantaranya sebagai Komisaris di PT Krakatau Steel (Persero) Tbk (2007-2009), sebagai Komisaris di PT Kertas Kraft Aceh (Persero) (2007-2009), sebagai Presiden Komisaris di PT Geodipa Energi (Persero) (2007-2009). Selain itu, Beliau juga menjabat sebagai Managing Director di PT Northstar Pacific Capital (2009-2012), sebagai Independen Komisaris dan Presiden Direktur di PT Indosat Tbk (2010-2017), serta sebagai Komisaris Independen di PT Asuransi Tugu Pratama Indonesia Tbk (2011-2013) Komisaris Independen di PT Sarana Menara Nusantara Tbk (Protelindo) (2018-2019), Chairman di Iflix Indonesia (2018-2020), dan Komisaris PT Solusi Sinergi Digital (2019-2022).&nbsp;</p>', NULL, 1, 'admin@gmail.com', NULL, '2025-11-28 09:43:53', '2025-11-28 09:43:53'),
(14, 'Vivek Sood', 'Member of Nomination and Remuneration Committee', 'Member of Nomination and Remuneration Committee', NULL, 5, 'https://linknet.co.id//storage/files/1/management/Vivek Sood.jpg', '<p>Having experience as the Executive Vice President and Group Chief Marketing Officer of Telenor Group, as CFO and CEO of Telenor India, CEO of Grameenphone (Bangladesh), and Chief Operating Officer and CFO of Tata AIA Life Insurance (India). Currently, serves as Group Chief Executive Officer (GCEO) and Managing Director of Axiata Group Berhad (Axiata) since March 2023 after serving as Joint Acting GCEO since June 2022 and as Group Chief Financial Officer (CFO) in 2017.</p>', '<p>Memiliki pengalaman sebagai Executive Vice President dan Group Chief Marketing Officer di Telenor Group, menjabat sebagai CFO dan CEO di Telenor India, menjabat sebagai CEO di Grameenphone (Bangladesh), serta Chief Operating Officer dan CFO di Tata AIA Life Insurance (India). Saat ini, menjabat sebagai Group Chief Executive Officer (GCEO) and Managing Director of Axiata Group Berhad (Axiata) sejak Maret 2023, setelah sebelumnya menjabat Joint Acting GCEO sejak Juni 2022 dan Group Chief Financial Officer (GCFO) pada 2017.</p>', NULL, 1, 'admin@gmail.com', NULL, '2025-11-28 09:44:29', '2025-11-28 09:44:29'),
(15, 'Thomas Hundt', 'Member of Nomination and Remuneration Committee', 'Member of Nomination and Remuneration Committee', NULL, 5, 'https://linknet.co.id//storage/files/1/management/Thomas Hundt.jpg', '<p>Having extensive experience in the telecommunications industry including at Siemens AG Germany from 1998 to 2007 with his last position as Director Commercial Sales, as Member of the Supervisory Board of Azerfon LLC Azerbaijan from 2005 to 2006, as Executive Project Manager and CFO CMO North -East Finance &amp; Control at Nokia Siemens Network GmBH &amp; Co. KG Germany from 2007 to 2008, as Member of the Advisory Board at AIESEC Cambodia from 2013 to 2019, as Member of the Council of the European Chamber of Commerce (Eurocham) Cambodia since 2011, as Vice President of the German Business Group (ADW) Cambodia since in 2010, and joined Axiata Group Company since 2014 and has held various director positions, with his last position currently being Group Chief Strategy &amp; Technology Officer at Axiata Group Berhad.</p>', '<p>Memiliki pengalaman luas di industri telekomunikasi diantaranya pada Siemens AG Jerman sejak tahun 1998 sampai dengan tahun 2007 dengan posisi terakhir sebagai Director Commercial Sales, sebagai Anggota Dewan Pengawasan Azerfon LLC Azerbaijan pada tahun 2005 sampai dengan tahun 2006, sebagai Executive Project Manager dan CFO CMO North-East Finance &amp; Control di Nokia Siemens Network GmBH &amp; Co. KG Jerman pada tahun 2007 sampai dengan tahun 2008, sebagai Anggota Dewan Penasihat di AIESEC Kamboja pada tahun 2013 sampai dengan tahun 2019, sebagai Anggota Dewan Kamar Dagang Eropa (Eurocham) Kamboja sejak tahun 2011, sebagai Vice President German Business Group (ADW) Kamboja sejak tahun 2010, dan bergabung bersama Axiata Group Company sejak tahun 2014 dan menjabat pada berbagai posisi direktur, dengan posisi terakhir saat ini sebagai Group Chief Strategy &amp; Technology Officer di Axiata Group Berhad.</p>', NULL, 1, 'admin@gmail.com', NULL, '2025-11-28 09:45:03', '2025-11-28 09:45:03');

