(45, 'Kalyana Medhira', 'Gusti', 'gigamanbyte@gmail.com', '0812 3999 8275', 'Student', 'AIESEC in Surabaya', 'business', 'AIESEC in Surabaya is an international non-profit non-partisipan organization that is passionate in empowering underprivileged youth especially locally in Surabaya. We also focus on SDGs based projects and impactful events. We aim to connect with meaningful partners to support our continuous work. Please contact us to connect more with us!', '210.57.214.98', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/144.0.0.0 Safari/537.36', '2026-02-11 09:59:48', '2026-02-11 09:59:48', '2026-02-11 09:59:48'),
(46, 'Ricky', 'Andian', 'ricky7andian@gmail.com', '0852 5744 1777', 'Customer', NULL, 'support', 'Ingin memindahkan pit hole didepan rumah saya, karena akan segera dilakukan renovasi namun belum mendapatkan tindak lanjut konkret', '157.85.210.89', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:147.0) Gecko/20100101 Firefox/147.0', '2026-02-14 03:50:25', '2026-02-14 03:50:25', '2026-02-14 03:50:25'),
(47, 'PAUL', 'MCADAM', 'pauleslteacher1@gmail.com', '0813 8174 6644', NULL, NULL, 'others', 'I had a Subscription from February 1, 2025 to January 31, 2026. I didn\'t renew substruction nor did anyone contact me from First Media. I was sent a bill on February 3 asking for payment for the month of February, but I didn\'t sign up for anymore service and disconnected my modem and TV box on January 31. I called First Media on February 6 and told them to pick up my tech stuff and they said they would. But nobody has come and you keep sending me bills. Please follow up.', '182.3.51.216', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/145.0.0.0 Safari/537.36 Edg/145.0.0.0/null', '2026-02-16 01:52:10', '2026-02-16 01:52:10', '2026-02-16 01:52:10'),
